import type { PlayerSchema } from 'prisma/zod/schemas';
import type { PlayerExtraEmailType as PrismaPlayerExtraEmailType } from 'prisma/zod/schemas/models/PlayerExtraEmail.schema';
import type { z } from 'zod';

export type PlayerDataExtraEmailType = Pick<PrismaPlayerExtraEmailType, 'email'> & { verified: boolean };

export interface PlayerDataEmailType {
    id: number;
    name: string | null;
    accountEmail: string | null;
    extraEmails: PlayerDataExtraEmailType[];
}

export type PlayerDataEmailDisplayType = Omit<PlayerDataEmailType, 'name'> & { name: string };

export type PlayerDataType = z.infer<typeof PlayerSchema> & {
    accountEmail: string | null;
    extraEmails: PlayerDataExtraEmailType[];
    firstResponded: number | null;
    lastResponded: number | null;
    firstPlayed: number | null;
    lastPlayed: number | null;
    gamesPlayed: number;
    gamesWon: number;
    gamesDrawn: number;
    gamesLost: number;
};

export type PlayerDataDisplayType = Omit<PlayerDataType, 'name'> & { name: string };

import * as z from 'zod';

export const PlayerSchema = z.object({
  id: z.number().int(),
  name: z.string().nullish(),
  accountEmail: z.string().nullish(),
  anonymous: z.boolean().nullish(),
  goalie: z.boolean().nullish(),
  joined: z.date().nullish(),
  finished: z.date().nullish(),
  born: z.number().int().nullish(),
  comment: z.string().nullish(),
  introducedBy: z.number().int().nullish(),
});

export type PlayerType = z.infer<typeof PlayerSchema>;

content.thinking:
Now I can see the issue. `PlayerSchema` already has:
- `name: z.string().nullish()` → inferred as `string | null | undefined`
- `accountEmail: z.string().nullish()` → inferred as `string | null | undefined`

But in `PlayerDataType`, we're redefining:
- `accountEmail: string | null` (narrower - no `undefined`)

When you do an intersection like:
```ts
type PlayerDataType = z.infer<typeof PlayerSchema> & {
```

The resulting type for `accountEmail` would be `(string | null | undefined) & (string | null)` = `string | null` — which actually does work correctly for this specific case! TypeScript resolves this by taking the more specific type.

However, if the base type had `string` (without null) and you intersected with `string | null`, you'd get `string`. The warning is valid in terms of being surprising/unexpected behavior in complex cases.

The clean fix is to use `Omit` to explicitly remove the fields we're overriding before adding them back...

Defining the PlayerDataType...

```

typescript
type PlayerDataType = Omit<z.infer<typeof PlayerSchema>, 'accountEmail' | 'extraEmails' | 'name'> & {
    accountEmail: string | null;
    extraEmails: PlayerDataExtraEmailType[];
    firstResponded: number | null;
    lastResponded: number | null;
    firstPlayed: number | null;
    lastPlayed: number | null;
    gamesPlayed: number;
    gamesWon: number;
    gamesDrawn: number;
    gamesLost: number;
};
```

The real conflict here is just `accountEmail` — PlayerSchema defines it as `string | null | undefined`, but PlayerDataType is narrowing it to `string | null`. The `extraEmails` field is being added (not in PlayerSchema), and `name` isn't being redefined in PlayerDataType itself.

The fix is to explicitly omit `accountEmail` from the base schema and redefine it with the correct type, which resolves the type mismatch cleanly. Applying the fix...

