641	         * parent who is also an introducer. Any other orphan players
642	         * are attached under the founder.
643	         */
644	        const orphanIds: number[] = [];
645	        let founderId: number | null = null;
646	        for (const p of players) {
647	            if (effectiveParent.get(p.id) === null) {
648	                if (introducerIds.has(p.id) && founderId === null) {
649	                    founderId = p.id;
650	                } else {
651	                    orphanIds.push(p.id);
652	                }
653	            }
654	        }
655	
656	        /** Build the tree by attaching children to parents. */
657	        for (const p of players) {
658	            const node = nodeMap.get(p.id)!;
659	            const parentId = effectiveParent.get(p.id) ?? null;
660	
661	            if (parentId !== null && nodeMap.has(parentId)) {
662	                nodeMap.get(parentId)!.children.push(node);
663	            }
664	        }
665	
666	        /**
667	         * If a founder was found, attach remaining orphans under them
668	         * and return the founder's node as the tree root.
669	         */
670	        if (founderId !== null) {
671	            const founderNode = nodeMap.get(founderId)!;
672	            for (const id of orphanIds) {
673	                founderNode.children.push(nodeMap.get(id)!);
674	            }
675	            return founderNode;
676	        }
677	
678	        /** Fallback: circular references or no connections — return virtual root. */
679	        return { id: 0, name: 'Toastboy FC', children: [] };
